module top_module (
    input clk,
    input reset,
    output [1:0] gray_count );reg [1:0] obf_binary_count;
    reg [1:0] gray_count_reg;

    always @(posedge clk) begin
        if (reset)
            obf_binary_count <= 2'b00;
        else
            obf_binary_count <= obf_binary_count + 1;
    end

    always @(*) begin
        gray_count_reg = {obf_binary_count[1], obf_binary_count[1] ^ obf_binary_count[0]};
    end

    assign gray_count = gray_count_reg;

endmodule
